mapper.select:
SELECT sensor_id AS sensorId, device_no AS deviceNo, channel_no AS channelNo,
       frequency AS frequency, temperature AS temperature,
       tension AS tension, strain_value AS strainValue, collect_time AS collectTime
FROM vibrating_wire_data
WHERE sensor_id = #{sensorId} AND deleted = 0
AND collect_time >= #{startTime}
AND collect_time <= #{endTime}
ORDER BY collect_time ASC
LIMIT #{limit}
